#include <bits/stdc++.h>
using namespace std;
stack<char> a;
int main() {
	string n;
	cin>>n;
	for(int i=0; i<n.size(); i++) {
		if(n[i]=='(') {
			a.push(n[i]);
		}
		if(n[i]==')') {
			if(a.empty()) {
				cout<<"NO";
				return 0;
			} else {
				a.pop();
			}
		}
	}
	if(a.empty()) {
		cout<<"YES";
	} else {
		cout<<"NO";
	}
	return 0;
}
